mapper.update:
UPDATE shipment
SET status = #{status}
WHERE orderNo = #{orderNo}
  AND status IN ('READY', 'SHIPPING')

mapper.select:
SELECT DISTINCT orderNo
FROM shipment
WHERE status = #{shipmentStatus}

SELECT sh.shipmentNo, sh.orderNo, sh.sellerUid, s.companyName AS sellerName, o.receiver, o.phone, CONCAT('[', o.zipCode, '] ', o.addr1, ' ', COALESCE(o.addr2, '')) AS address, sh.courierName, sh.trackingNo, sh.status, sh.shippedAt, sh.createdAt, COALESCE(SUM(si.quantity), 0) AS itemCount FROM shipment sh JOIN `order` o ON o.orderNo = sh.orderNo LEFT JOIN seller s ON s.uid = sh.sellerUid LEFT JOIN shipment_item si ON si.shipmentNo = sh.shipmentNo WHERE sh.shipmentNo = #{shipmentNo}
AND sh.sellerUid = #{sellerUid}
GROUP BY sh.shipmentNo, sh.orderNo, sh.sellerUid, s.companyName, o.receiver, o.phone, o.zipCode, o.addr1, o.addr2, sh.courierName, sh.trackingNo, sh.status, sh.shippedAt, sh.createdAt

SELECT oi.orderItemNo, oi.orderNo, oi.prodVariantId, oi.prodNo AS prodNo, oi.productName AS prodName, oi.optionText, p.thumb1FileId, oi.sellerUid, s.companyName AS sellerName, si.quantity AS count, oi.originalPrice AS originalPrice, oi.discountRate AS discountRate, GREATEST((oi.originalPrice * si.quantity) - (oi.price * si.quantity), 0) AS discountAmount, oi.price, oi.total, oi.shippingFee, oi.itemStatus, sh.shipmentNo, sh.courierName, sh.trackingNo, sh.status AS shipmentStatus, o.createdAt FROM shipment_item si JOIN shipment sh ON sh.shipmentNo = si.shipmentNo JOIN order_item oi ON oi.orderItemNo = si.orderItemNo JOIN `order` o ON o.orderNo = oi.orderNo LEFT JOIN product p ON p.prodNo = oi.prodNo LEFT JOIN seller s ON s.uid = oi.sellerUid WHERE si.shipmentNo = #{shipmentNo}
AND oi.sellerUid = #{sellerUid}
ORDER BY oi.orderItemNo ASC
